  SELECT setval(pg_get_serial_sequence('ali_follows','id'), COALESCE((SELECT MAX(id) FROM ali_follows),0)+1, false);
  SELECT setval(pg_get_serial_sequence('ali_space_invites','id'), COALESCE((SELECT MAX(id) FROM ali_space_invites),0)+1, false);
  SELECT setval(pg_get_serial_sequence('ali_spaces','id'), COALESCE((SELECT MAX(id) FROM ali_spaces),0)+1, false);
  SELECT setval(pg_get_serial_sequence('ali_space_participants','id'), COALESCE((SELECT MAX(id) FROM ali_space_participants),0)+1, false);
  SELECT setval(pg_get_serial_sequence('ali_space_signals','id'), COALESCE((SELECT MAX(id) FROM ali_space_signals),0)+1, false);
  SELECT setval(pg_get_serial_sequence('ali_articles','id'), COALESCE((SELECT MAX(id) FROM ali_articles),0)+1, false);
  SELECT setval(pg_get_serial_sequence('users_activity','id'), COALESCE((SELECT MAX(id) FROM users_activity),0)+1, false);
  SELECT setval(pg_get_serial_sequence('ads_revenue','id'), COALESCE((SELECT MAX(id) FROM ads_revenue),0)+1, false);

